import{_ as t,C as n,o as l,c as s,j as o,E as a,a as i,a3 as g}from"./chunks/framework.DACwFHq9.js";const P=JSON.parse('{"title":"渲染设置","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/rendering.md","filePath":"user-guide/tools/llm-chat/settings/rendering.md","lastUpdated":1781266243000}'),d={name:"user-guide/tools/llm-chat/settings/rendering.md"},u={id:"渲染设置",tabindex:"-1"};function c(m,e,h,p,f,_){const r=n("LIcon");return l(),s("div",null,[o("h1",u,[a(r,{name:"Zap",size:"28"}),e[0]||(e[0]=i(" 渲染设置 ",-1)),e[1]||(e[1]=o("a",{class:"header-anchor",href:"#渲染设置","aria-label":'Permalink to "<LIcon name="Zap" size="28" /> 渲染设置"'},"​",-1))]),e[2]||(e[2]=g('<p>渲染设置模块决定了聊天消息如何被解析、展示以及在流式生成过程中的性能表现。</p><h2 id="核心引擎-core-engines" tabindex="-1">核心引擎 (Core Engines) <a class="header-anchor" href="#核心引擎-core-engines" aria-label="Permalink to &quot;核心引擎 (Core Engines)&quot;">​</a></h2><ul><li><strong>消息渲染器</strong>: <ul><li>选择 Markdown 解析引擎版本。不同版本在解析速度和对复杂语法（如数学公式、图表）的支持上有所差异。</li></ul></li><li><strong>代码块高亮</strong>: <ul><li>消息代码块固定使用 CodeMirror，以降低启动和长会话渲染成本，并适配流式打字机效果。</li></ul></li></ul><h2 id="性能与平滑度-performance-smoothing" tabindex="-1">性能与平滑度 (Performance &amp; Smoothing) <a class="header-anchor" href="#性能与平滑度-performance-smoothing" aria-label="Permalink to &quot;性能与平滑度 (Performance &amp; Smoothing)&quot;">​</a></h2><ul><li><strong>渲染节流 (Throttling)</strong>: <ul><li><strong>说明</strong>: 控制流式输出时 AST 树的更新频率。</li><li><strong>作用</strong>: 设置为 100ms 左右可显著降低生成超长文本时的 CPU 负载，防止界面假死。</li></ul></li><li><strong>流式平滑化 (Streaming Smoothing)</strong>: <ul><li><strong>功能</strong>: 通过语义分块技术，消除流式输出时常见的“文字跳跃”感，使打字机效果如丝般顺滑。</li></ul></li><li><strong>HTML 预览冻结 (Freezer)</strong>: <ul><li><strong>核心机制</strong>: 当会话中出现多个 HTML 预览（如连续生成多个网页）时，自动冻结非最新的预览容器。</li><li><strong>优势</strong>: 极大降低了 CPU 和内存开销，同时保持最近 N 条消息的预览依然可交互。</li></ul></li></ul><h2 id="安全与护栏-safety-guard" tabindex="-1">安全与护栏 (Safety Guard) <a class="header-anchor" href="#安全与护栏-safety-guard" aria-label="Permalink to &quot;安全与护栏 (Safety Guard)&quot;">​</a></h2><ul><li><strong>渲染安全护栏</strong>: <ul><li><strong>说明</strong>: 自动检测并限制异常节点数、深度嵌套及解析超时。</li><li><strong>作用</strong>: 防止模型因输出恶意构造的特殊字符或无限循环内容而导致前端崩溃。</li></ul></li><li><strong>HTML 安全策略</strong>: <ul><li><strong>CDN 本地化</strong>: 拦截并重定向常用 CDN 资源至本地，提升加载速度并支持离线预览。</li><li><strong>危险标签限制</strong>: 严格过滤 <code>script</code>、<code>iframe</code> 等标签，除非你手动开启“允许危险标签”开关。</li></ul></li></ul><h2 id="交互特性" tabindex="-1">交互特性 <a class="header-anchor" href="#交互特性" aria-label="Permalink to &quot;交互特性&quot;">​</a></h2><ul><li><strong>性能指标 (Metrics)</strong>: 开启后可在消息底部看到实时的生成速度 (tokens/s) 及首字响应延迟 (TTFT)。</li><li><strong>无缝模式 (Seamless Mode)</strong>: 移除 HTML 预览的外框，使其看起来像原生 UI 一样嵌入在消息流中。</li></ul><hr><div class="warning custom-block"><p class="custom-block-title">注意</p><p>开启“允许危险 HTML 标签”可能会让 AI 生成的内容执行恶意脚本。请仅在调试或完全信任模型输出的情况下使用。</p></div>',11))])}const S=t(d,[["render",c]]);export{P as __pageData,S as default};
